// Importações principais do Firebase
import { initializeApp } from "firebase/app";
import {
  getAuth,
  onAuthStateChanged, // ✅ Import adicionado
} from "firebase/auth";
import {
  getFirestore,
  doc,     // ✅ Import adicionado
  getDoc,  // ✅ Import adicionado
  setDoc,  // ✅ Import adicionado
} from "firebase/firestore";

const firebaseConfig = {
  apiKey: "AIzaSyCot5JdiY-QYPGOBJ75UYYu4GkgAUZgSpY",
  authDomain: "votacao-sandiego.firebaseapp.com",
  projectId: "votacao-sandiego",
  storageBucket: "votacao-sandiego.firebasestorage.app",
  messagingSenderId: "936386447775",
  appId: "1:936386447775:web:2f5024e5be258549ced5aa",
  measurementId: "G-N2VLLTK69K"
};

export const observarUsuario = (callback) => {
  return onAuthStateChanged(auth, (user) => {
    callback(user);
  });
};
const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getFirestore(app);

onAuthStateChanged(auth, async (user) => {
  if (user) {
    const ref = doc(db, "usuarios", user.uid);
    const snap = await getDoc(ref);

    if (!snap.exists()) {
      await setDoc(ref, {
        email: user.email,
        nome: user.displayName || "",
        role: "user", // padrão
        criadoEm: new Date(),
      });
      console.log(`✅ Usuário criado automaticamente no Firestore: ${user.email}`);
    }
  }
});

export default app;
